module top_module (
    input [15:0] a,
    input [15:0] b,
    input cin,
    output [15:0] sum,
    output cout
);

    wire c0, c1, c2;

    bcd_faddt digit0 (
        .a(a[3:0]),
        .b(b[3:0]),
        .cin(cin),
        .sum(sum[3:0]),
        .cout(c0)
    );

    bcd_faddt digit1 (
        .a(a[7:4]),
        .b(b[7:4]),
        .cin(c0),
        .sum(sum[7:4]),
        .cout(c1)
    );

    bcd_faddt digit2 (
        .a(a[11:8]),
        .b(b[11:8]),
        .cin(c1),
        .sum(sum[11:8]),
        .cout(c2)
    );

    bcd_faddt digit3 (
        .a(a[15:12]),
        .b(b[15:12]),
        .cin(c2),
        .sum(sum[15:12]),
        .cout(cout)
    );

endmodule

module bcd_faddt (
    input [3:0] a,
    input [3:0] b,
    input cin,
    output [3:0] sum,
    output cout
);

    wire [4:0] temp = a + b + cin;
    assign cout = (temp > 9);
    assign sum = (temp > 9) ? (temp[3:0] + 4'd6) : temp[3:0];

endmodule

module sc_cu (
    input [5:0] op,
    input [5:0] func,
    input z,
    output reg wmem,
    output reg wreg,
    output reg regrt,
    output reg m2reg,
    output reg [3:0] aluc,
    output reg shift,
    output reg aluimm,
    output reg [1:0] pcsource,
    output reg jal,
    output reg sext
);

    always @(*) begin
        // Default control values
        wmem = 0;
        wreg = 0;
        regrt = 0;
        m2reg = 0;
        aluc = 4'b0010; // ADD
        shift = 0;
        aluimm = 0;
        pcsource = 2'b00; // PC+4
        jal = 0;
        sext = 0;

        case (op)
            6'b000000: begin // R-type
                regrt = 0; // Destination is rd
                wreg = 1;  // Most R-type write to register
                case (func)
                    6'b100000: aluc = 4'b0010; // add
                    6'b100010: aluc = 4'b0110; // sub
                    6'b100100: aluc = 4'b0000; // and
                    6'b100101: aluc = 4'b0001; // or
                    6'b100110: aluc = 4'b0011; // xor
                    6'b000000: begin // sll
                        aluc = 4'b0100;
                        shift = 1;
                        aluimm = 1; // Use shamt
                    end
                    6'b000010: begin // srl
                        aluc = 4'b0101;
                        shift = 1;
                        aluimm = 1;
                    end
                    6'b000011: begin // sra
                        aluc = 4'b1101;
                        shift = 1;
                        aluimm = 1;
                    end
                    6'b001000: begin // jr
                        wreg = 0; // No register write
                        pcsource = 2'b11; // Jump register
                    end
                    default: aluc = 4'b0010; // Default to ADD
                endcase
            end
            6'b001000: begin // addi
                wreg = 1;
                regrt = 1;
                aluimm = 1;
                aluc = 4'b0010; // ADD
                sext = 1; // Sign-extend
            end
            6'b001100: begin // andi
                wreg = 1;
                regrt = 1;
                aluimm = 1;
                aluc = 4'b0000; // AND
                sext = 0; // Zero-extend
            end
            6'b001101: begin // ori
                wreg = 1;
                regrt = 1;
                aluimm = 1;
                aluc = 4'b0001; // OR
                sext = 0;
            end
            6'b001110: begin // xori
                wreg = 1;
                regrt = 1;
                aluimm = 1;
                aluc = 4'b0011; // XOR
                sext = 0;
            end
            6'b100011: begin // lw
                wreg = 1;
                regrt = 1;
                aluimm = 1;
                aluc = 4'b0010; // ADD
                m2reg = 1; // Memory to register
                sext = 1;
            end
            6'b101011: begin // sw
                wmem = 1; // Write memory
                regrt = 1;
                aluimm = 1;
                aluc = 4'b0010; // ADD
                sext = 1;
            end
            6'b000100: begin // beq
                aluimm = 0; // Use registers
                aluc = 4'b0110; // SUB for comparison
                sext = 1;
                if (z) pcsource = 2'b01; // Branch taken
            end
            6'b000101: begin // bne
                aluimm = 0;
                aluc = 4'b0110;
                sext = 1;
                if (!z) pcsource = 2'b01;
            end
            6'b001111: begin // lui
                wreg = 1;
                regrt = 1;
                aluimm = 1;
                aluc = 4'b0100; // SLL
                shift = 1; // Shift by 16
                sext = 0; // Zero-extend immediate
            end
            6'b000010: begin // j
                pcsource = 2'b10; // Jump
            end
            6'b000011: begin // jal
                wreg = 1;
                regrt = 1; // Overridden by jal
                jal = 1; // Write to $ra
                pcsource = 2'b10;
            end
            // Defaults are set initially
        endcase
    end

endmodule
